INSERT INTO `wp_ytazrs7z61_postmeta` VALUES ('7','6','panels_data','a:3:{s:7:\"widgets\";a:6:{i:0;a:10:{s:5:\"title\";s:0:\"\";s:4:\"text\";s:1405:\"<h1 style=\"text-align: center;\">HOPE IN NORTH EAST CHESHIRE</h1>\n\n<hr />\n\n<h4 style=\"line-height:1.4em;\">Hope in North East Cheshire (Hope) encourages shared initiatives in mission and service and organises joint gatherings for worship and prayer. It also responds to requests for information, help and funding, working closely with many voluntary organisations, a number represented here, and the statutory authorities.\n<br />\nIncorporating Churches Together in Macclesfield and Bollington, and affiliated to Churches Together in Britain and Ireland, Hope was established in 2009 bringing together some thirty-nine Churches of many denominations in Macclesfield, Bollington and the surrounding villages. The Church Leaders meet regularly for prayer, worship, fellowship and discussion, while small groups of Leaders and lay people plan Hope’s priorities, review progress and relationships, and manage its finances.\n<br />\nHope involves lots of volunteers, many from the local Churches, in a wide range of initiatives which any one Church would find difficult to sustain. It encourages like-minded people to come together to respond to their calling and to share their passions to make things happen for the benefit of the community.\n<br />\n<span style=\"color: #00ccff;\">Proclaiming the Gospel through Social Action in Macclesfield and Bollington and the surrounding villages.</span></h4>\";s:20:\"text_selected_editor\";s:4:\"html\";s:5:\"autop\";b:1;s:12:\"_sow_form_id\";s:13:\"56d05dfaf043c\";s:19:\"_sow_form_timestamp\";s:13:\"1514883684307\";s:2:\"id\";s:17:\"sow-editor-610000\";s:11:\"option_name\";s:17:\"widget_sow-editor\";s:22:\"so_sidebar_emulator_id\";s:17:\"sow-editor-610000\";s:11:\"panels_info\";a:7:{s:5:\"class\";s:31:\"SiteOrigin_Widget_Editor_Widget\";s:3:\"raw\";b:0;s:4:\"grid\";i:0;s:4:\"cell\";i:0;s:2:\"id\"