INSERT INTO `wp_ytazrs7z61_postmeta` VALUES ('321','84','panels_data','a:3:{s:7:\"widgets\";a:2:{i:0;a:6:{s:5:\"title\";s:0:\"\";s:4:\"text\";s:2915:\"<p><strong>Background and Aims</strong><br />Just Drop-In is the Millennium Project of Churches Together in Macclesfield, with the support of 14 churches. It provides a \'one-stop shop\' for 12-25 year of age (and their family) in and around Macclesfield where they can access information and get specialist advice on a whole range of issues, in a welcoming and informal setting in the town centre. It opened in November 2001 at 17a Chestergate, leased for 5 years. We are now in brand new premises with the Youth Service at 33 Great King Street, Macclesfield, SK11 6PN.</p><p><strong>Operation</strong><br />JDI employs a full-time Co-ordinator, supported by a part-time volunteer co-ordinator/administrator and approximately 35 volunteers working 3-hour shifts. It is open every day except Sunday. Although run by the churches, it is in partnership with Cheshire Youth Services, Macclesfield Accommodation Care and Concern (the Glegg Street Hostel) and other agencies who are available at the centre on specified days of the week. Two youth workers from Cheshire Youth Service are generally at JDI.</p><p>Young people can be helped with accommodation, employment, drug and alcohol abuse, bullying, relationships, benefits, mental health and any other areas in which they need information and advice. Six computers are available for access to information on the internet and for use for homework, CV’s, projects, presentations, job applications, etc. The Cyber Café has proved very popular. The number of weekly visits has increased from an initial 20 to a current 120 or more.</p><p>The co-ordinator identified the lack of a professional counselling service for young people in the area. After intensive consultation with agencies, extra funding was sought and obtained. Lisa Gaffney, an experienced BACP accredited counsellor was appointed part time and started the service in July 2004. She is kept very busy.</p><p>Just Drop-In is open Monday, Wednesday, Friday from 1400-1700; Tuesday and Thursday 1200-1800; Saturday 1000-1200.</p><p><strong>Accreditation</strong><br />Just Drop-In has obtained the Legal Services Commission Quality Kitemark and Validation by the Cheshire Council for Voluntary Youth Service</p><p><strong>Finance</strong><br />Just Drop-In opened with a Community Fund Grant which covered start-up and running costs for three years. This expired in March 2004. Since then we have been using our reserve fund built up by local fund raising, donations and grants.</p><p>The Trustees are now looking to secure the longer term future of Just Drop-In, which has now established itself as a focal point for the youth of the town. In three years it can be said to have helped many young lives, and in many cases has made a vital difference.</p><p>We are always looking for fund-raising initiatives and support.</p><p>Visit the <a href=\"http://www.justdropin.co.uk/\">Just Drop-In web site</a></p>\";s:20:\"text_selected_editor\";s:7:\"tinymce\";s:5:\"autop\";b:1;s:12:\"_sow_form_id\";s:13:\"56c879f9b3c8f\";s:11:\"panels_info\";a:6:{s:5:\"class\";s:31:\"SiteOrigin_Widget_Editor_Widget\";s:3:\"raw\";b:0;s:4:\"grid\";i:0;s:4:\"cell\";i:0;s:2:\"id\";i:0;s:5:\"style\";a:1:{s:18:\"background_display\";s:4:\"tile\";}}}i:1;a:13:{s:5:\"image\";i:75;s:14:\"image_fallback\";s:0:\"\";s:4:\"size\";s:4:\"full\";s:5:\"align\";s:5:\"right\";s:5:\"title\";s:0:\"\";s:14:\"title_position\";s:6:\"hidden\";s:3:\"alt\";s:0:\"\";s:3:\"url\";s:0:\"\";s:5:\"bound\";b:1;s:12:\"_sow_form_id\";s:13:\"56c87a9a78c99\";s:10:\"new_window\";b:0;s:10:\"full_width\";b:0;s:11:\"panels_info\";a:6:{s:5:\"class\";s:30:\"SiteOrigin_Widget_Image_Widget\";s:3:\"raw\";b:0;s:4:\"grid\";i:0;s:4:\"cell\";i:1;s:2:\"id\";i:1;s:5:\"style\";a:1:{s:18:\"background_display\";s:4:\"tile\";}}}}s:5:\"grids\";a:1:{i:0;a:2:{s:5:\"cells\";i:2;s:5:\"style\";a:2:{s:23:\"background_image_repeat\";s:0:\"\";s:9:\"no_margin\";s:0:\"\";}}}s:10:\"grid_cells\";a:2:{i:0;a:2:{s:4:\"grid\";i:0;s:6:\"weight\";d:0.61803399209205734;}i:1;a:2:{s:4:\"grid\";i:0;s:6:\"weight\";d:0.38196600790794272;}}}');
INSERT INTO `wp_ytazrs7z61_postmeta` VALUES ('322','61','_panels_data_preview','a:3:{s:7:\"widgets\";a:3:{i:0;a:6:{s:5:\"title\";s:0:\"\";s:4:\"text\";s:1132:\"<h3>‘People deserve care and love in their time of need’</h3><p>We work together with the management of Macclesfield Town Centre and the Police to help people, whoever they are and whatever their situation, by listening, caring, offering practical help or referring them to specialist agencies.</p><p>As volunteers from the local churches we walk around the town on Saturday nights (from 10.30pm - 3.00am):</p><ul><li>providing a Christian presence</li><li>giving free bottles of water</li><li>helping out with free flip-flops for those who need them</li><li>lending a listening ear to those whose evening has not turned out so well</li><li>giving simple first aid</li><li>inviting those who need a warm drink back to the United Reformed Church, our centre</li><li>referring those who are in dire need to the emergency services</li></ul><p> </p><p>I would like to consider helping with Street Angels Macclesfield on a Saturday evening:</p><ul><li>Please contact your church leader or administrator</li><li>email streetangelsmacclesfield@gmail.com</li><li>or call Pip Mosscrop Street Angels coordinator on 07715 495701</li></ul>\";s:20:\"text_selected_editor\";s:7:\"tinymce\";s:5:\"autop\";b:1;s:12:\"_sow_form_id\";s:13:\"56c87b5190047\";s:11:\"panels_info\";a:6:{s:5:\"class\";s:31:\"SiteOrigin_Widget_Editor_Widget\";s:3:\"raw\";b:0;s:4:\"grid\";i:0;s:4:\"cell\";i:0;s:2:\"id\";i:0;s:5:\"style\";a:1:{s:18:\"background_display\";s:4:\"tile\";}}}i:1;a:13:{s:5:\"image\";i:74;s:14:\"image_fallback\";s:0:\"\";s:4:\"size\";s:4:\"full\";s:5:\"align\";s:5:\"right\";s:5:\"title\";s:0:\"\";s:14:\"title_position\";s:6:\"hidden\";s:3:\"alt\";s:0:\"\";s:3:\"url\";s:0:\"\";s:5:\"bound\";b:1;s:12:\"_sow_form_id\";s:13:\"56c87b68cc3ec\";s:11:\"panels_info\";a:5:{s:5:\"class\";s:30:\"SiteOrigin_Widget_Image_Widget\";s:4:\"grid\";i:0;s:4:\"cell\";i:1;s:2:\"id\";i:1;s:5:\"style\";a:2:{s:27:\"background_image_attachment\";b:0;s:18:\"background_display\";s:4:\"tile\";}}s:10:\"new_window\";b:0;s:10:\"full_width\";b:0;}i:2;a:13:{s:5:\"image\";i:130;s:14:\"image_fallback\";s:0:\"\";s:4:\"size\";s:4:\"full\";s:5:\"align\";s:7:\"default\";s:5:\"title\";s:0:\"\";s:14:\"title_position\";s:6:\"hidden\";s:3:\"alt\";s:0:\"\";s:3:\"url\";s:25:\"http://www.sa-cni.org.uk/\";s:5:\"bound\";b:1;s:12:\"_sow_form_id\";s:13:\"56d0675aa7935\";s:11:\"panels_info\";a:5:{s:5:\"class\";s:30:\"SiteOrigin_Widget_Image_Widget\";s:4:\"grid\";i:0;s:4:\"cell\";i:1;s:2:\"id\";i:2;s:5:\"style\";a:2:{s:27:\"background_image_attachment\";b:0;s:18:\"background_display\";s:4:\"tile\";}}s:10:\"new_window\";b:0;s:10:\"full_width\";b:0;}}s:5:\"grids\";a:1:{i:0;a:2:{s:5:\"cells\";i:2;s:5:\"style\";a:2:{s:23:\"background_image_repeat\";s:0:\"\";s:9:\"no_margin\";s:0:\"\";}}}s:10:\"grid_cells\";a:2:{i:0;a:2:{s:4:\"grid\";i:0;s:6:\"weight\";d:0.61803399209206;}i:1;a:2:{s:4:\"grid\";i:0;s:6:\"weight\";d:0.38196600790794;}}}');
