INSERT INTO `wp_ytazrs7z61_postmeta` VALUES ('339','126','panels_data','a:3:{s:7:\"widgets\";a:2:{i:0;a:6:{s:5:\"title\";s:0:\"\";s:4:\"text\";s:733:\"<p>Cre8 is an independent charity based on the Moss Rose Estate in Macclesfield. We provide projects and activities for young people and their families. Our work is aimed towards empowering young people and adults in the local area to <strong>make change happen</strong> for themselves and also for their local neighbourhood.</p><p>The Cre8 community is made up of a wide range of people from different backgrounds, who work or volunteer from full time to just a couple of hours over the holidays. From the wounderful, generous and passionate volunteers who are the backbone of everything we do, to the slightly crazy but dedicated and very patient staff team - everyone who has any involvement with Cre8 is a part of the team.</p>\";s:20:\"text_selected_editor\";s:7:\"tinymce\";s:5:\"autop\";b:1;s:12:\"_sow_form_id\";s:13:\"56c87cc37c5a3\";s:11:\"panels_info\";a:5:{s:5:\"class\";s:31:\"SiteOrigin_Widget_Editor_Widget\";s:4:\"grid\";i:0;s:4:\"cell\";i:0;s:2:\"id\";i:0;s:5:\"style\";a:2:{s:27:\"background_image_attachment\";b:0;s:18:\"background_display\";s:4:\"tile\";}}}i:1;a:13:{s:5:\"image\";i:71;s:14:\"image_fallback\";s:0:\"\";s:4:\"size\";s:4:\"full\";s:5:\"align\";s:5:\"right\";s:5:\"title\";s:0:\"\";s:14:\"title_position\";s:6:\"hidden\";s:3:\"alt\";s:0:\"\";s:3:\"url\";s:0:\"\";s:5:\"bound\";b:1;s:12:\"_sow_form_id\";s:13:\"56c87ca811f5d\";s:10:\"new_window\";b:0;s:10:\"full_width\";b:0;s:11:\"panels_info\";a:6:{s:5:\"class\";s:30:\"SiteOrigin_Widget_Image_Widget\";s:3:\"raw\";b:0;s:4:\"grid\";i:0;s:4:\"cell\";i:1;s:2:\"id\";i:1;s:5:\"style\";a:1:{s:18:\"background_display\";s:4:\"tile\";}}}}s:5:\"grids\";a:1:{i:0;a:2:{s:5:\"cells\";i:2;s:5:\"style\";a:0:{}}}s:10:\"grid_cells\";a:2:{i:0;a:2:{s:4:\"grid\";i:0;s:6:\"weight\";d:0.61803399209206;}i:1;a:2:{s:4:\"grid\";i:0;s:6:\"weight\";d:0.38196600790794;}}}');
INSERT INTO `wp_ytazrs7z61_postmeta` VALUES ('340','78','_panels_data_preview','a:3:{s:7:\"widgets\";a:2:{i:0;a:6:{s:5:\"title\";s:0:\"\";s:4:\"text\";s:1886:\"<div><b><u></u></b>With the support of Churches and volunteers in Macclesfield, Cheshire Streetwise is combating poverty through the provision of furniture and other household items to those in need in the areas of Macclesfield and Congleton.</div><div> </div><div>The furniture project contributes items to the Emergency Assistance Scheme operated by Cheshire East and also provides furniture to individuals and families through referrals from local agencies and churches.</div><div> </div><div>Volunteers currently collect and deliver furniture two to three days a week and run a shop at Gilchrist Avenue, Macclesfield for four days a week (Monday, Tuesday, Thursday 10.00-4.00, Saturday 10.00-12.00). Visitors are always welcome for a cup of tea and a chat.</div><div> </div><div>Cheshire Streetwise is committed to providing education, support and counselling to a wide range of children and adults with a variety of needs and also provides tuition, a skills cafe, counselling, foodbank and signposting service.</div><div> </div><div>To arrange collections, referrals or for general enquiries call 07469 176811</div><div> </div><div> </div><div><i>Like: Facebook at <a href=\"http://www.facebook.com/CheshireFurnitureReuse\" target=\"_blank\" rel=\"nofollow\" shape=\"rect\" data-saferedirecturl=\"https://www.google.com/url?q=http://www.facebook.com/CheshireFurnitureReuse&amp;source=gmail&amp;ust=1470158779612000&amp;usg=AFQjCNH4yTeAaHB3Pi7UJOJq_l_tXZShyQ\">www.facebook.com/<wbr></wbr>CheshireFurnitureReuse</a></i></div><div><i>Follow: CheshreReuse @CFRFCoordinator</i></div><div><i>Visit: <a href=\"http://www.cfrf.org.uk/\" target=\"_blank\" rel=\"nofollow\" shape=\"rect\" data-saferedirecturl=\"https://www.google.com/url?q=http://www.cfrf.org.uk/&amp;source=gmail&amp;ust=1470158779612000&amp;usg=AFQjCNEdvpjqJqgsTDIqk5PSj5l1uTeeyw\">http://www.cfrf.org.uk/</a></i></div>\";s:20:\"text_selected_editor\";s:7:\"tinymce\";s:5:\"autop\";b:1;s:12:\"_sow_form_id\";s:13:\"56d05b6e93fba\";s:11:\"panels_info\";a:6:{s:5:\"class\";s:31:\"SiteOrigin_Widget_Editor_Widget\";s:3:\"raw\";b:0;s:4:\"grid\";i:0;s:4:\"cell\";i:0;s:2:\"id\";i:0;s:5:\"style\";a:1:{s:18:\"background_display\";s:4:\"tile\";}}}i:1;a:13:{s:5:\"image\";i:200;s:14:\"image_fallback\";s:0:\"\";s:4:\"size\";s:4:\"full\";s:5:\"align\";s:7:\"default\";s:5:\"title\";s:0:\"\";s:14:\"title_position\";s:6:\"hidden\";s:3:\"alt\";s:0:\"\";s:3:\"url\";s:0:\"\";s:5:\"bound\";b:1;s:12:\"_sow_form_id\";s:13:\"579f88a46200b\";s:11:\"panels_info\";a:5:{s:5:\"class\";s:30:\"SiteOrigin_Widget_Image_Widget\";s:4:\"grid\";i:0;s:4:\"cell\";i:1;s:2:\"id\";i:1;s:5:\"style\";a:2:{s:27:\"background_image_attachment\";b:0;s:18:\"background_display\";s:4:\"tile\";}}s:10:\"new_window\";b:0;s:10:\"full_width\";b:0;}}s:5:\"grids\";a:1:{i:0;a:2:{s:5:\"cells\";i:2;s:5:\"style\";a:2:{s:23:\"background_image_repeat\";s:0:\"\";s:9:\"no_margin\";s:0:\"\";}}}s:10:\"grid_cells\";a:2:{i:0;a:2:{s:4:\"grid\";i:0;s:6:\"weight\";d:0.61803399209206;}i:1;a:2:{s:4:\"grid\";i:0;s:6:\"weight\";d:0.38196600790794;}}}');
