INSERT INTO `wp_ytazrs7z61_postmeta` VALUES ('342','78','panels_data','a:3:{s:7:\"widgets\";a:2:{i:0;a:6:{s:5:\"title\";s:0:\"\";s:4:\"text\";s:1886:\"<div><b><u></u></b>With the support of Churches and volunteers in Macclesfield, Cheshire Streetwise is combating poverty through the provision of furniture and other household items to those in need in the areas of Macclesfield and Congleton.</div><div> </div><div>The furniture project contributes items to the Emergency Assistance Scheme operated by Cheshire East and also provides furniture to individuals and families through referrals from local agencies and churches.</div><div> </div><div>Volunteers currently collect and deliver furniture two to three days a week and run a shop at Gilchrist Avenue, Macclesfield for four days a week (Monday, Tuesday, Thursday 10.00-4.00, Saturday 10.00-12.00). Visitors are always welcome for a cup of tea and a chat.</div><div> </div><div>Cheshire Streetwise is committed to providing education, support and counselling to a wide range of children and adults with a variety of needs and also provides tuition, a skills cafe, counselling, foodbank and signposting service.</div><div> </div><div>To arrange collections, referrals or for general enquiries call 07469 176811</div><div> </div><div> </div><div><i>Like: Facebook at <a href=\"http://www.facebook.com/CheshireFurnitureReuse\" target=\"_blank\" rel=\"nofollow\" shape=\"rect\" data-saferedirecturl=\"https://www.google.com/url?q=http://www.facebook.com/CheshireFurnitureReuse&amp;source=gmail&amp;ust=1470158779612000&amp;usg=AFQjCNH4yTeAaHB3Pi7UJOJq_l_tXZShyQ\">www.facebook.com/<wbr></wbr>CheshireFurnitureReuse</a></i></div><div><i>Follow: CheshreReuse @CFRFCoordinator</i></div><div><i>Visit: <a href=\"http://www.cfrf.org.uk/\" target=\"_blank\" rel=\"nofollow\" shape=\"rect\" data-saferedirecturl=\"https://www.google.com/url?q=http://www.cfrf.org.uk/&amp;source=gmail&amp;ust=1470158779612000&amp;usg=AFQjCNEdvpjqJqgsTDIqk5PSj5l1uTeeyw\">http://www.cfrf.org.uk/</a></i></div>\";s:20:\"text_selected_editor\";s:7:\"tinymce\";s:5:\"autop\";b:1;s:12:\"_sow_form_id\";s:13:\"56d05b6e93fba\";s:11:\"panels_info\";a:6:{s:5:\"class\";s:31:\"SiteOrigin_Widget_Editor_Widget\";s:3:\"raw\";b:0;s:4:\"grid\";i:0;s:4:\"cell\";i:0;s:2:\"id\";i:0;s:5:\"style\";a:1:{s:18:\"background_display\";s:4:\"tile\";}}}i:1;a:13:{s:5:\"image\";i:200;s:14:\"image_fallback\";s:0:\"\";s:4:\"size\";s:4:\"full\";s:5:\"align\";s:6:\"center\";s:5:\"title\";s:0:\"\";s:14:\"title_position\";s:6:\"hidden\";s:3:\"alt\";s:0:\"\";s:3:\"url\";s:0:\"\";s:5:\"bound\";b:1;s:12:\"_sow_form_id\";s:13:\"579f88a46200b\";s:11:\"panels_info\";a:5:{s:5:\"class\";s:30:\"SiteOrigin_Widget_Image_Widget\";s:4:\"grid\";i:0;s:4:\"cell\";i:1;s:2:\"id\";i:1;s:5:\"style\";a:2:{s:27:\"background_image_attachment\";b:0;s:18:\"background_display\";s:4:\"tile\";}}s:10:\"new_window\";b:0;s:10:\"full_width\";b:0;}}s:5:\"grids\";a:1:{i:0;a:2:{s:5:\"cells\";i:2;s:5:\"style\";a:2:{s:23:\"background_image_repeat\";s:0:\"\";s:9:\"no_margin\";s:0:\"\";}}}s:10:\"grid_cells\";a:2:{i:0;a:2:{s:4:\"grid\";i:0;s:6:\"weight\";d:0.61803399209206;}i:1;a:2:{s:4:\"grid\";i:0;s:6:\"weight\";d:0.38196600790794;}}}');
INSERT INTO `wp_ytazrs7z61_postmeta` VALUES ('347','129','panels_data','a:3:{s:7:\"widgets\";a:2:{i:0;a:6:{s:5:\"title\";s:0:\"\";s:4:\"text\";s:1121:\"<h3>‘People deserve care and love in their time of need’</h3><p>We work together with the management of Macclesfield Town Centre and the Police to help people, whoever they are and whatever their situation, by listening, caring, offering practical help or referring them to specialist agencies. As volunteers from the local churches we walk around the town on Saturday nights (from 10.30pm - 3.00am):</p><ul><li>providing a Christian presence</li><li>giving free bottles of water</li><li>helping out with free flip-flops for those who need</li><li>lending a listening ear to those whose evening has not turned out so well</li><li>giving simple first aid</li><li>inviting those who need a warm drink back to the United Reformed Church, our centre</li><li>referring those who are in dire need to the emergency services</li></ul><p> </p><p>I would like to consider helping with Street Angels Macclesfield on a Saturday evening:</p><ul><li>Please contact your church leader or administrator</li><li>email streetangelsmacclesfield@gmail.com</li><li>or call Pip Mosscrop Street Angels coordinator on 07715 495701</li></ul>\";s:20:\"text_selected_editor\";s:7:\"tinymce\";s:5:\"autop\";b:1;s:12:\"_sow_form_id\";s:13:\"56c87b5190047\";s:11:\"panels_info\";a:6:{s:5:\"class\";s:31:\"SiteOrigin_Widget_Editor_Widget\";s:3:\"raw\";b:0;s:4:\"grid\";i:0;s:4:\"cell\";i:0;s:2:\"id\";i:0;s:5:\"style\";a:1:{s:18:\"background_display\";s:4:\"tile\";}}}i:1;a:13:{s:5:\"image\";i:74;s:14:\"image_fallback\";s:0:\"\";s:4:\"size\";s:4:\"full\";s:5:\"align\";s:5:\"right\";s:5:\"title\";s:0:\"\";s:14:\"title_position\";s:6:\"hidden\";s:3:\"alt\";s:0:\"\";s:3:\"url\";s:0:\"\";s:5:\"bound\";b:1;s:12:\"_sow_form_id\";s:13:\"56c87b68cc3ec\";s:10:\"new_window\";b:0;s:10:\"full_width\";b:0;s:11:\"panels_info\";a:6:{s:5:\"class\";s:30:\"SiteOrigin_Widget_Image_Widget\";s:3:\"raw\";b:0;s:4:\"grid\";i:0;s:4:\"cell\";i:1;s:2:\"id\";i:1;s:5:\"style\";a:1:{s:18:\"background_display\";s:4:\"tile\";}}}}s:5:\"grids\";a:1:{i:0;a:2:{s:5:\"cells\";i:2;s:5:\"style\";a:2:{s:23:\"background_image_repeat\";s:0:\"\";s:9:\"no_margin\";s:0:\"\";}}}s:10:\"grid_cells\";a:2:{i:0;a:2:{s:4:\"grid\";i:0;s:6:\"weight\";d:0.61803399209205734;}i:1;a:2:{s:4:\"grid\";i:0;s:6:\"weight\";d:0.38196600790794272;}}}');
