INSERT INTO `wp_ytazrs7z61_postmeta` VALUES ('350','131','panels_data','a:3:{s:7:\"widgets\";a:2:{i:0;a:6:{s:5:\"title\";s:0:\"\";s:4:\"text\";s:1132:\"<h3>‘People deserve care and love in their time of need’</h3><p>We work together with the management of Macclesfield Town Centre and the Police to help people, whoever they are and whatever their situation, by listening, caring, offering practical help or referring them to specialist agencies.</p><p>As volunteers from the local churches we walk around the town on Saturday nights (from 10.30pm - 3.00am):</p><ul><li>providing a Christian presence</li><li>giving free bottles of water</li><li>helping out with free flip-flops for those who need them</li><li>lending a listening ear to those whose evening has not turned out so well</li><li>giving simple first aid</li><li>inviting those who need a warm drink back to the United Reformed Church, our centre</li><li>referring those who are in dire need to the emergency services</li></ul><p> </p><p>I would like to consider helping with Street Angels Macclesfield on a Saturday evening:</p><ul><li>Please contact your church leader or administrator</li><li>email streetangelsmacclesfield@gmail.com</li><li>or call Pip Mosscrop Street Angels coordinator on 07715 495701</li></ul>\";s:20:\"text_selected_editor\";s:7:\"tinymce\";s:5:\"autop\";b:1;s:12:\"_sow_form_id\";s:13:\"56c87b5190047\";s:11:\"panels_info\";a:5:{s:5:\"class\";s:31:\"SiteOrigin_Widget_Editor_Widget\";s:4:\"grid\";i:0;s:4:\"cell\";i:0;s:2:\"id\";i:0;s:5:\"style\";a:2:{s:27:\"background_image_attachment\";b:0;s:18:\"background_display\";s:4:\"tile\";}}}i:1;a:13:{s:5:\"image\";i:74;s:14:\"image_fallback\";s:0:\"\";s:4:\"size\";s:4:\"full\";s:5:\"align\";s:5:\"right\";s:5:\"title\";s:0:\"\";s:14:\"title_position\";s:6:\"hidden\";s:3:\"alt\";s:0:\"\";s:3:\"url\";s:0:\"\";s:5:\"bound\";b:1;s:12:\"_sow_form_id\";s:13:\"56c87b68cc3ec\";s:10:\"new_window\";b:0;s:10:\"full_width\";b:0;s:11:\"panels_info\";a:6:{s:5:\"class\";s:30:\"SiteOrigin_Widget_Image_Widget\";s:3:\"raw\";b:0;s:4:\"grid\";i:0;s:4:\"cell\";i:1;s:2:\"id\";i:1;s:5:\"style\";a:1:{s:18:\"background_display\";s:4:\"tile\";}}}}s:5:\"grids\";a:1:{i:0;a:2:{s:5:\"cells\";i:2;s:5:\"style\";a:2:{s:23:\"background_image_repeat\";s:0:\"\";s:9:\"no_margin\";s:0:\"\";}}}s:10:\"grid_cells\";a:2:{i:0;a:2:{s:4:\"grid\";i:0;s:6:\"weight\";d:0.61803399209206;}i:1;a:2:{s:4:\"grid\";i:0;s:6:\"weight\";d:0.38196600790794;}}}');
INSERT INTO `wp_ytazrs7z61_postmeta` VALUES ('351','87','_panels_data_preview','a:3:{s:7:\"widgets\";a:2:{i:0;a:6:{s:5:\"title\";s:0:\"\";s:4:\"text\";s:938:\"<p>The HOPE Centre welcome everyone to it\'s coffee shop and Christian bookshop, selling books, cards, and gifts. Based at Park Green, Macclesfield, it provides a beacon of hope to the people of Macclesfield.</p><p>We stock a range of Christian resources (available and to order) including Bibles in various translations, Bible reading notes, Junior church, church resources, holiday clubs, messy church, study guides for house groups. We have Bible commentaries, concordances, study guides, Childrens activity books, pocket money gifts and novelty items, CDs and music resources.</p><p>A large selection of cards is available for all occasions: Gifts including first communion, confirmation, baptism, jewellry, games, seasonal presents, stationery, mass cards and rosaries. </p><p>We will also order any book or Bible from our suppliers.</p><p>Visit <a href=\"http://www.hopecentremacclesfield.org.uk\">The Hope Centre website</a>.</p>\";s:20:\"text_selected_editor\";s:7:\"tinymce\";s:5:\"autop\";b:1;s:12:\"_sow_form_id\";s:13:\"56d069bfe953f\";s:11:\"panels_info\";a:5:{s:5:\"class\";s:31:\"SiteOrigin_Widget_Editor_Widget\";s:4:\"grid\";i:0;s:4:\"cell\";i:0;s:2:\"id\";i:0;s:5:\"style\";a:2:{s:27:\"background_image_attachment\";b:0;s:18:\"background_display\";s:4:\"tile\";}}}i:1;a:13:{s:5:\"image\";i:86;s:14:\"image_fallback\";s:0:\"\";s:4:\"size\";s:4:\"full\";s:5:\"align\";s:7:\"default\";s:5:\"title\";s:0:\"\";s:14:\"title_position\";s:6:\"hidden\";s:3:\"alt\";s:0:\"\";s:3:\"url\";s:0:\"\";s:5:\"bound\";b:1;s:12:\"_sow_form_id\";s:13:\"56d069ae3acab\";s:10:\"new_window\";b:0;s:10:\"full_width\";b:0;s:11:\"panels_info\";a:6:{s:5:\"class\";s:30:\"SiteOrigin_Widget_Image_Widget\";s:3:\"raw\";b:0;s:4:\"grid\";i:0;s:4:\"cell\";i:1;s:2:\"id\";i:1;s:5:\"style\";a:1:{s:18:\"background_display\";s:4:\"tile\";}}}}s:5:\"grids\";a:1