INSERT INTO `wp_ytazrs7z61_postmeta` VALUES ('552','198','panels_data','a:3:{s:7:\"widgets\";a:2:{i:0;a:6:{s:5:\"title\";s:0:\"\";s:4:\"text\";s:413:\"<p>Weekly, and very successfully, over many years, volunteers have collected used furniture from donor houses and delivered to needy people in the Macclesfield Borough.<br /><br />Please ring 07775 941809 for Enquiries, Furniture requests or offers<br /><br />An answer phone will accept your call, which will be returned the same day.<br />We always welcome new volunteers<br />On Fridays 8.30 am to 12.30 pm</p>\";s:20:\"text_selected_editor\";s:7:\"tinymce\";s:5:\"autop\";b:1;s:12:\"_sow_form_id\";s:13:\"56d05b6e93fba\";s:11:\"panels_info\";a:5:{s:5:\"class\";s:31:\"SiteOrigin_Widget_Editor_Widget\";s:4:\"grid\";i:0;s:4:\"cell\";i:0;s:2:\"id\";i:0;s:5:\"style\";a:2:{s:27:\"background_image_attachment\";b:0;s:18:\"background_display\";s:4:\"tile\";}}}i:1;a:5:{s:6:\"filter\";s:1:\"1\";s:4:\"text\";s:187:\"<img class=\"alignright wp-image-76 size-full\" src=\"http://open-me.info/hinec-test/wp-content/uploads/logo-furnaround-317-160.png\" alt=\"logo-furnaround-317-160\" width=\"317\" height=\"160\" />\";s:5:\"title\";s:0:\"\";s:4:\"type\";s:6:\"visual\";s:11:\"panels_info\";a:5:{s:5:\"class\";s:31:\"SiteOrigin_Widget_Editor_Widget\";s:3:\"raw\";b:0;s:4:\"grid\";i:0;s:4:\"cell\";i:1;s:2:\"id\";i:1;}}}s:5:\"grids\";a:1:{i:0;a:2:{s:5:\"cells\";i:2;s:5:\"style\";a:2:{s:23:\"background_image_repeat\";s:0:\"\";s:9:\"no_margin\";s:0:\"\";}}}s:10:\"grid_cells\";a:2:{i:0;a:2:{s:4:\"grid\";i:0;s:6:\"weight\";d:0.61803399209205734;}i:1;a:2:{s:4:\"grid\";i:0;s:6:\"weight\";d:0.38196600790794272;}}}');
