s:7:\"onclick\";s:0:\"\";s:3:\"rel\";s:0:\"\";s:24:\"so_field_container_state\";s:6:\"closed\";}s:12:\"_sow_form_id\";s:13:\"5a48f82783e64\";s:19:\"_sow_form_timestamp\";s:13:\"1514731649384\";s:11:\"panels_info\";a:6:{s:5:\"class\";s:31:\"SiteOrigin_Widget_Button_Widget\";s:4:\"grid\";i:2;s:4:\"cell\";i:2;s:2:\"id\";i:8;s:9:\"widget_id\";s:36:\"ee0630a9-0227-4af8-98c8-b91797b9d79d\";s:5:\"style\";a:2:{s:27:\"background_image_attachment\";b:0;s:18:\"background_display\";s:4:\"tile\";}}s:10:\"new_window\";b:0;}i:9;a:7:{s:5:\"title\";s:0:\"\";s:4:\"text\";s:1374:\"<h1 style=\"text-align: center;\">HOPE IN NORTH EAST CHESHIRE</h1>\n<hr />\n<p>Hope in North East Cheshire (Hope) encourages shared initiatives in mission and service and organises joint gatherings for worship and prayer. It also responds to requests for information, help and funding, working closely with many voluntary organisations, a number represented here, and the statutory authorities.</p>\n<p>Incorporating Churches Together in Macclesfield and Bollington, and affiliated to Churches Together in Britain and Ireland, Hope was established in 2009 bringing together some thirty-nine Churches of many denominations in Macclesfield, Bollington and the surrounding villages. The Church Leaders meet regularly for prayer, worship, fellowship and discussion, while small groups of Leaders and lay people plan Hope’s priorities, review progress and relationships, and manage its finances.</p>\n<p>Hope involves lots of volunteers, many from the local Churches, in a wide range of initiatives which any one Church would find difficult to sustain. It encourages like-minded people to come together to respond to their calling and to share their passions to make things happen for the benefit of the community.</p>\n<p><span style=\"color: #00ccff;\">Proclaiming the Gospel through Social Action in Macclesfield and Bollington and the surrounding villages.</span></p>\";s:20:\"text_selected_editor\";s:4:\"html\";s:5:\"autop\";b:1;s:12:\"_sow_form_id\";s:13:\"56d05dfaf043c\";s:19:\"_sow_form_timestamp\";s:13:\"1514729526446\";s:11:\"panels_info\";a:7:{s:5:\"class\";s:31:\"SiteOrigin_Widget_Editor_Widget\";s:3:\"raw\";b:0;s:4:\"grid\";i:3;s:4:\"cell\";i:0;s:2:\"id\";i:9;s:9:\"widget_id\";s:36:\"5e601e8d-1f90-49ec-b671-fb13c8d6ef10\";s:5:\"style\";a:1:{s:18:\"background_display\";s:4:\"tile\";}}}}s:5:\"grids\";a:4:{i:0;a:2:{s:5:\"cells\";i:3;s:5:\"style\";a:0:{}}i:1;a:2:{s:5:\"cells\";i:3;s:5:\"style\";a:2:{s:23:\"background_image_repeat\";s:0:\"\";s:9:\"no_margin\";s:0:\"\";}}i:2;a:2:{s:5:\"cells\";i:3;s:5:\"style\";a:0:{}}i:3;a:2:{s:5:\"cells\";i:1;s:5:\"style\";a:0:{}}}s:10:\"grid_cells\";a:10:{i:0;a:4:{s:4:\"grid\";i:0;s:5:\"index\";i:0;s:6:\"weight\";d:0.33333333333332998;s:5:\"style\";a:0:{}}i:1;a:4:{s:4:\"grid\";i:0;s:5:\"index\";i:1;s:6:\"weight\";d:0.33333333333332998;s:5:\"style\";a:0:{}}i:2;a:4:{s:4:\"grid\";i:0;s:5:\"index\";i:2;s:6:\"weight\";d:0.33333333333332998;s:5:\"style\";a:0:{}}i:3;a:4:{s:4:\"grid\";i:1;s:5:\"index\";i:0;s:6:\"weight\";d:0.33333333333332998;s:5:\"style\";a:0:{}}i:4;a:4:{s:4:\"grid\";i:1;s:5:\"index\";i:1;s:6:\"weight\";d:0.33333333333332998;s:5:\"style\";a:0:{}}i:5;a:4:{s:4:\"grid\";i:1;s:5:\"index\";i:2;s:6:\"weight\";d:0.33333333333332998;s:5:\"style\";a:0:{}}i:6;a:4:{s:4:\"grid\";i:2;s:5:\"index\";i:0;s:6:\"weight\";d:0.33333333333332998;s:5:\"style\";a:0:{}}i:7;a:4:{s:4:\"grid\";i:2;s:5:\"index\";i:1;s:6:\"weight\";d:0.33333333333332998;s:5:\"style\";a:0:{}}i:8;a:4:{s:4:\"grid\";i:2;s:5:\"index\";i:2;s:6:\"weight\";d:0.33333333333332998;s:5:\"style\";a:0:{}}i:9;a:4:{s:4:\"grid\";i:3;s:5:\"index\";i:0;s:6:\"weight\";i:1;s:5:\"style\";a:0:{}}}}');
