INSERT INTO `wp_ytazrs7z61_postmeta` VALUES ('860','411','panels_data','a:3:{s:7:\"widgets\";a:3:{i:0;a:8:{s:5:\"title\";s:0:\"\";s:4:\"text\";s:1132:\"<h3>‘People deserve care and love in their time of need’</h3><p>We work together with the management of Macclesfield Town Centre and the Police to help people, whoever they are and whatever their situation, by listening, caring, offering practical help or referring them to specialist agencies.</p><p>As volunteers from the local churches we walk around the town on Saturday nights (from 10.30pm - 3.00am):</p><ul><li>providing a Christian presence</li><li>giving free bottles of water</li><li>helping out with free flip-flops for those who need them</li><li>lending a listening ear to those whose evening has not turned out so well</li><li>giving simple first aid</li><li>inviting those who need a warm drink back to the United Reformed Church, our centre</li><li>referring those who are in dire need to the emergency services</li></ul><p> </p><p>I would like to consider helping with Street Angels Macclesfield on a Saturday evening:</p><ul><li>Please contact your church leader or administrator</li><li>email streetangelsmacclesfield@gmail.com</li><li>or call Pip Mosscrop Street Angels coordinator on 07715 495701</li></ul>\";s:20:\"text_selected_editor\";s:7:\"tinymce\";s:5:\"autop\";b:1;s:12:\"_sow_form_id\";s:13:\"56c87b5190047\";s:11:\"panels_info\";a:7:{s:5:\"class\";s:31:\"SiteOrigin_Widget_Editor_Widget\";s:3:\"raw\";b:0;s:4:\"grid\";i:0;s:4:\"cell\";i:0;s:2:\"id\";i:0;s:9:\"widget_id\";s:36:\"73d52dbd-31a4-402f-b207-95fd95a210dc\";s:5:\"style\";a:1:{s:18:\"background_display\";s:4:\"tile\";}}s:22:\"so_sidebar_emulator_id\";s:18:\"sow-editor-6110000\";s:11:\"option_name\";s:17:\"widget_sow-editor\";}i:1;a:15:{s:5:\"image\";i:74;s:14:\"image_fallback\";s:0:\"\";s:4:\"size\";s:4:\"full\";s:5:\"align\";s:5:\"right\";s:5:\"title\";s:0:\"\";s:14:\"title_position\";s:6:\"hidden\";s:3:\"alt\";s:0:\"\";s:3:\"url\";s:0:\"\";s:5:\"bo