INSERT INTO `wp_ytazrs7z61_posts` VALUES ('8','3','2015-02-27 23:23:24','2015-02-27 23:23:24','<h4>Editable Home Page</h4>\r\n<p class=\"text\">You can edit this home page using our free, drag and drop Page Builder, or simply disable it to fall back to a standard blog. It\'s a powerful page building experience.</p>\r\n<a class=\"more-button\" href=\"#\">Start Editing <i></i></a>\r\n<h4>Loads of Icons</h4>\r\n<p class=\"text\">This widget uses FontAwesome - giving you hundreds of icons. Or you could disable the icon and use your own image image. Great for testimonials.</p>\r\n<a class=\"more-button\" href=\"#\">Example Button <i></i></a>\r\n<h4>Saves You Time</h4>\r\n<p class=\"text\">Building your pages using a drag and drop page builder is a great experience that will save you time. Time is valuable. Don\'t waste it.</p>\r\n<a class=\"more-button\" href=\"#\">Test Button <i></i></a>\r\n<h1>This Is A Headline Widget</h1>\r\n<h3>You can customize it and put it where ever you want</h3>\r\nThere are a lot of widgets bundled with Page Builder. You can use them to bring your pages to life.','Home','','inherit','closed','closed','','6-revision-v1','','','2015-02-27 23:23:24','2015-02-27 23:23:24','','6','http://open-me.info/hinec-test/6-revision-v1/',0,'revision','',0);
