INSERT INTO `wp_ytazrs7z61_posts` VALUES ('59','3','2015-03-02 18:47:00','2015-03-02 18:47:00','Brings together some thirty-nine Churches in Macclesfield and Bollington and the surrounding villages who work together in mission in their communities. The objectives of Hope in North East Cheshire represent a visible sign of the Churches\' commitment to each other by:\r\n<ul>\r\n	<li>providing a Church Leaders’ Forum for consultation and policy-making</li>\r\n	<li>encouraging shared worship and prayer, learning, service and evangelism</li>\r\n	<li>promoting initiatives in mission and service</li>\r\n	<li>encouraging local groupings of Churches</li>\r\n	<li>strengthening sustainable working relationships and reinforcing long-term partnerships</li>\r\n</ul>\r\nBetween them, other Christian organisations, their local communities and the providers of educational, fire, health, housing, policing and social services. Hope in North East Cheshire is affiliated to Churches Together in Britain and Ireland.','Objectives','','publish','closed','closed','','objectives','','','2015-03-02 18:47:00','2015-03-02 18:47:00','','0','http://open-me.info/hinec-test/?page_id=59',0,'page','',0);
INSERT INTO `wp_ytazrs7z61_posts` VALUES ('60','3','2015-03-02 18:47:00','2015-03-02 18:47:00','Brings together some thirty-nine Churches in Macclesfield and Bollington and the surrounding villages who work together in mission in their communities. The objectives of Hope in North East Cheshire represent a visible sign of the Churches\' commitment to each other by:\r\n<ul>\r\n	<li>providing a Church Leaders’ Forum for consultation and policy-making</li>\r\n	<li>encouraging shared worship and prayer, learning, service and evangelism</li>\r\n	<li>promoting initiatives in mission and service</li>\r\n	<li>encouraging local groupings of Churches</li>\r\n	<li>strengthening sustainable working relationships and reinforcing long-term partnerships</li>\r\n</ul>\r\nBetween them, other Christian organisations, their local communities and the providers of educational, fire, health, housing, policing and social services. Hope in North East Cheshire is affiliated to Churches Together in Britain and Ireland.','Objectives','','inherit','closed','closed','','59-revision-v1','','','2015-03-02 18:47:00','2015-03-02 18:47:00','','59','http://open-me.info/hinec-test/59-revision-v1/',0,'revision','',0);
INSERT INTO `wp_ytazrs7z61_posts` VALUES ('61','3','2015-03-02 18:58:55','2015-03-02 18:58:55','<div id=\"pl-61\"  class=\"panel-layout\" ><div id=\"pg-61-0\"  class=\"panel-grid panel-no-style\"  data-style=\"{&quot;full_height&quot;:&quot;&quot;,&quot;background_image_repeat&quot;:&quot;&quot;,&quot;no_margin&quot;:&quot;&quot;}\" ><div id=\"pgc-61-0-0\"  class=\"panel-grid-cell\"  data-weight=\"0.61803399209206\" ><div id=\"panel-61-0-0-0\" class=\"so-panel widget widget_sow-editor panel-first-child panel-last-child\" data-index=\"0\" data-style=\"{&quot;background_display&quot;:&quot;tile&quot;}\" ><div\n			\n			class=\"so-widget-sow-editor so-widget-sow-editor-base\"\n			\n		>\n<div class=\"siteorigin-widget-tinymce textwidget\">\n	<h3>‘People deserve care and love in their time of need’</h3><p>We work together with the management of Macclesfield Town Centre and the Police to help people, whoever they are and whatever their situation, by listening, caring, offering practical help or referring them to specialist agencies.</p><p>As volunteers from the local churches we walk around the town on Saturday nights (from 10.30pm - 3.00am):</p><ul><li>providing a Christian presence</li><li>giving free bottles of water</li><li>helping out with free flip-flops for those who need them</li><li>lending a listening ear to those whose evening has not turned out so well</li><li>giving simple first aid</li><li>inviting those who need a warm drink back to the United Reformed Church, our centre</li><li>referring those who are in dire need to the emergency services</li></ul><p> </p><p>I would like to consider helping with Street Angels Macclesfield on a Saturday evening:</p><ul><li>Please contact your church leader or administrator</li><li>email streetangelsmacclesfield@gmail.com</li><li>or call Pip Mosscrop Street Angels coordinator on 07715 495701</li></ul></div>\n</div></div></div><div id=\"pgc-61-0-1\"  class=\"panel-grid-cell\"  data-weight=\"0.38196600790794\" ><div id=\"panel-61-0-1-0\" class=\"so-panel widget widget_sow-image panel-first-child\" data-index=\"1\" data-style=\"{&quot;background_image_attachment&quot;:false,&quot;background_display&quot;:&quot;tile&quot;}\" >[siteorigin_widget class=\"SiteOrigin_Widget_Image_Widget\"]<input type=\"hidden\" value=\"{&quot;instance&quot;:{&quot;image&quot;:74,&quot;image_fallback&quot;:&quot;&quot;,&quot;size&quot;:&quot;full&quot;,&quot;align&quot;:&quot;right&quot;,&quot;title&quot;:&quot;&quot;,&quot;title_position&quot;:&quot;hidden&quot;,&quot;alt&quot;:&quot;&quot;,&quot;url&quot;:&quot;&quot;,&quot;bound&quot;:true,&quot;_sow_form_id&quot;:&quot;56c87b68cc3ec&quot;,&quot;new_window&quot;:false,&quot;full_width&quot;:false,&quot;so_sidebar_emulator_id&quot;:&quot;sow-image-6110001&quot;,&quot;option_name&quot;:&quot;widget_sow-image&quot;},&quot;args&quot;:{&quot;before_widget&quot;:&quot;&lt;div id=\\&quot;panel-61-0-1-0\\&quot; class=\\&quot;so-panel widget widget_sow-image panel-first-child\\&quot; data-index=\\&quot;1\\&quot; data-style=\\&quot;{&amp;quot;background_image_attachment&amp;quot;:false,&amp;quot;background_display&amp;quot;:&amp;quot;tile&amp;quot;}\\&quot; &gt;&quot;,&quot;after_widget&quot;:&quot;&lt;\\/div&gt;&quot;,&quot;before_title&quot;:&quot;&lt;h3 class=\\&quot;widget-title\\&quot;&gt;&quot;,&quot;after_title&quot;:&quot;&lt;\\/h3&gt;&quot;,&quot;widget_id&quot;:&quot;widget-0-1-0&quot;}}\" />[/siteorigin_widget]</div><div id=\"panel-61-0-1-1\" class=\"so-panel widget widget_sow-image panel-last-child\" data-index=\"2\" data-style=\"{&quot;background_image_attachment&quot;:false,&quot;background_display&quot;:&quot;tile&quot;,&quot;background_image_size&quot;:&quot;full&quot;,&quot;background_image_opacity&quot;:&quot;100&quot;,&quot;border_thickness&quot;:&quot;1px&quot;}\" >[siteorigin_widget class=\"SiteOrigin_Widget_Image_Widget\"]<input type=\"hidden\" value=\"{&quot;instance&quot;:{&quot;image&quot;:130,&quot;image_fallback&quot;:&quot;&quot;,&quot;size