INSERT INTO `wp_ytazrs7z61_posts` VALUES ('64','3','2015-03-02 19:03:06','2015-03-02 19:03:06','<h3>‘People deserve care and love in their time of need’</h3>\r\nWe work together with the management of Macclesfield Town Centre and the Police to help people, whoever they are and whatever their situation, by listening, caring, offering practical help or referring them to specialist agencies. As volunteers from the local churches we walk around the town on Saturday nights (from 10.30pm - 3.00am):\r\n<ul>\r\n	<li>providing a Christian presence</li>\r\n	<li>giving free bottles of water</li>\r\n	<li>helping out with free flip-flops for those who need</li>\r\n	<li>lending a listening ear to those whose evening has not turned out so well</li>\r\n	<li>giving simple first aid</li>\r\n	<li>inviting those who need a warm drink back to the United Reformed Church, our centre</li>\r\n	<li>referring those who are in dire need to the emergency services</li>\r\n</ul>\r\n&nbsp;\r\n\r\nI would like to consider helping with Street Angels Macclesfield on a Saturday evening:\r\n<ul>\r\n	<li>Please contact your church leader or administrator</li>\r\n	<li>email streetangelsmacclesfield@gmail.com</li>\r\n	<li>or call Pip Mosscrop Street Angels coordinator on 07715 495701</li>\r\n</ul>','Street Angels','','inherit','closed','closed','','61-revision-v1','','','2015-03-02 19:03:06','2015-03-02 19:03:06','','61','http://open-me.info/hinec-test/61-revision-v1/',0,'revision','',0);
