INSERT INTO `wp_ytazrs7z61_posts` VALUES ('83','3','2015-03-02 19:41:24','2015-03-02 19:41:24','<img class=\"alignright size-full wp-image-70\" src=\"http://open-me.info/hinec-test/wp-content/uploads/logo-open-the-book-317-160.jpg\" alt=\"logo-open- the-book-317-160\" width=\"317\" height=\"160\" />','Open The Book','','inherit','closed','closed','','66-revision-v1','','','2015-03-02 19:41:24','2015-03-02 19:41:24','','66','http://open-me.info/hinec-test/66-revision-v1/',0,'revision','',0);
INSERT INTO `wp_ytazrs7z61_posts` VALUES ('84','3','2015-03-02 19:43:07','2015-03-02 19:43:07','<p><strong>Background and Aims</strong><br>\r\nJust Drop-In is the Millennium Project of Churches Together in Macclesfield, with the support of 14 churches. It provides a \'one-stop shop\' for 12-25 year of age (and their family) in and around Macclesfield where they can access information and get specialist advice on a whole range of issues, in a welcoming and informal setting in the town centre. It opened in November 2001 at 17a Chestergate, leased for 5 years. We are now in brand new premises with the Youth Service at 33 Great King Street, Macclesfield, SK11 6PN.</p>\r\n<p><strong>Operation</strong><br>\r\nJDI employs a full-time Co-ordinator, supported by a part-time volunteer co-ordinator/administrator and approximately 35 volunteers working 3-hour shifts. It is open every day except Sunday. Although run by the churches, it is in partnership with Cheshire Youth Services, Macclesfield Accommodation Care and Concern (the Glegg Street Hostel) and other agencies who are available at the centre on specified days of the week. Two youth workers from Cheshire Youth Service are generally at JDI.</p>\r\n<p>Young people can be helped with accommodation, employment, drug and alcohol abuse, bullying, relationships, benefits, mental health and any other areas in which they need information and advice. Six computers are available for access to information on the internet and for use for homework, CV’s, projects, presentations, job applications, etc. The Cyber Café has proved very popular. The number of weekly visits has increased from an initial 20 to a current 120 or more.</p>\r\n<p>The co-ordinator identified the lack of a professional counselling service for young people in the area. After intensive consultation with agencies, extra funding was sought and obtained. Lisa Gaffney, an experienced BACP accredited counsellor was appointed part time and started the service in July 2004. She is kept very busy.</p>\r\n<p>Just Drop-In is open Monday, Wednesday, Friday from 1400-1700; Tuesday and Thursday 1200-1800; Saturday 1000-1200.</p>\r\n<p><strong>Accreditation</strong><br>\r\nJust Drop-In has obtained the Legal Services Commission Quality Kitemark and Validation by the Cheshire Council for Voluntary Youth Service</p>\r\n<p><strong>Finance</strong><br>\r\nJust Drop-In opened with a Community Fund Grant which covered start-up and running costs for three years. This expired in March 2004. Since then we have been using our reserve fund built up by local fund raising, donations and grants.</p>\r\n<p>The Trustees are now looking to secure the longer term future of Just Drop-In, which has now established itself as a focal point for the youth of the town. In three years it can be said to have helped many young lives, and in many cases has made a vital difference.</p>\r\n<p>We are always looking for fund-raising initiatives and support.</p>\r\n<p>Visit the <a href=\"http://www.justdropin.co.uk/\">Just Drop-In web site</a></p>\r\n<img src=\"http://open-me.info/hinec.org.uk-v2/wp-content/uploads/logo-just-drop-in-317-160.png\" width=\"317\" height=\"160\" srcset=\"http://open-me.info/hinec.org.uk-v2/wp-content/uploads/logo-just-drop-in-317-160-300x151.png 300w, http://open-me.info/hinec.org.uk-v2/wp-content/uploads/logo-just-drop-in-317-160.png 317w\" class=\"so-widget-image\">','Just Drop In','','publish','closed','closed','','just-drop-in','','','2016-02-20 14:46:12','2016-02-20 14:46:12','','0','http://open-me.info/hinec-test/?page_id=84',0,'page','',0);
