INSERT INTO `wp_ytazrs7z61_posts` VALUES ('87','3','2015-03-05 22:13:58','2015-03-05 22:13:58','<p>The HOPE Centre welcome everyone to it\'s coffee shop and Christian bookshop, selling books, cards, and gifts. Based at Park Green, Macclesfield, it provides a beacon of hope to the people of Macclesfield.</p>\r\n<p>We stock a range of Christian resources (available and to order) including Bibles in various translations, Bible reading notes, Junior church, church resources, holiday clubs, messy church, study guides for house groups.&nbsp;We have Bible commentaries, concordances, study guides,&nbsp;Childrens activity books, pocket money gifts and novelty items,&nbsp;CDs and music resources.</p>\r\n<p>A large selection of cards is available&nbsp;for all occasions: Gifts including first communion, confirmation, baptism, jewellry, games, seasonal presents, stationery, mass cards and rosaries.&nbsp;</p>\r\n<p>We will also order any book or Bible from our suppliers.</p>\r\n<p>Visit <a href=\"http://www.hopecentremacclesfield.org.uk\">The Hope Centre website</a>.</p>\r\n<img src=\"http://open-me.info/hinec.org.uk-v2/wp-content/uploads/logo-hope-centre-317-160.jpg\" width=\"316\" height=\"160\" srcset=\"http://open-me.info/hinec.org.uk-v2/wp-content/uploads/logo-hope-centre-317-160-300x152.jpg 300w, http://open-me.info/hinec.org.uk-v2/wp-content/uploads/logo-hope-centre-317-160.jpg 316w\" class=\"so-widget-image\">','The Hope Centre','','publish','closed','closed','','the-hope-centre','','','2016-02-26 15:18:09','2016-02-26 15:18:09','','0','http://open-me.info/hinec-test/?page_id=87',0,'page','',0);
