INSERT INTO `wp_ytazrs7z61_posts` VALUES ('126','3','2016-02-26 14:00:54','2016-02-26 14:00:54','<p>Cre8 is an independent charity based on the Moss Rose Estate in Macclesfield. We provide projects and activities for young people and their families. Our work is aimed towards empowering young people and adults in the local area to&nbsp;<strong>make change happen</strong> for themselves and also for their local neighbourhood.</p>\r\n<p>The Cre8 community is made up of a wide range of people from different backgrounds, who work or volunteer from full time to just a couple of hours over the holidays.&nbsp;From the wounderful, generous and passionate volunteers who are the backbone of everything we do, to the slightly crazy but dedicated and very patient staff team - everyone who has any involvement with Cre8 is a part of the team.</p>\r\n<p>Visit the <a href=\"http://www.cre8macclesfield.org/\">CRE8 website</a>.</p>\r\n<img src=\"http://open-me.info/hinec.org.uk-v2/wp-content/uploads/logo-cre8-317-160.jpg\" width=\"317\" height=\"161\" srcset=\"http://open-me.info/hinec.org.uk-v2/wp-content/uploads/logo-cre8-317-160-300x152.jpg 300w, http://open-me.info/hinec.org.uk-v2/wp-content/uploads/logo-cre8-317-160.jpg 317w\" class=\"so-widget-image\">','CRE8','','inherit','closed','closed','','122-revision-v1','','','2016-02-26 14:00:54','2016-02-26 14:00:54','','122','http://open-me.info/hinec.org.uk-v2/122-revision-v1/',0,'revision','',0);
INSERT INTO `wp_ytazrs7z61_posts` VALUES ('128','3','2016-02-26 14:06:49','2016-02-26 14:06:49','<p>Weekly, and very successfully, over many years, volunteers have collected used furniture from donor houses and delivered to needy people in the Macclesfield Borough.</p>\r\n<p>Please ring 07775 941809 for Enquiries, Furniture requests or offers</p>\r\n<p>An answer phone will accept your call, which will be returned the same day.<br>\r\nWe always welcome new volunteers<br>\r\nOn Fridays 8.30 am to 12.30 pm</p>\r\n<p><img class=\"alignright wp-image-76 size-full\" src=\"http://open-me.info/hinec-test/wp-content/uploads/logo-furnaround-317-160.png\" alt=\"logo-furnaround-317-160\" width=\"317\" height=\"160\" srcset=\"http://open-me.info/hinec.org.uk-v2/wp-content/uploads/logo-furnaround-317-160-300x151.png 300w, http://open-me.info/hinec.org.uk-v2/wp-content/uploads/logo-furnaround-317-160.png 317w\" sizes=\"(max-width: 317px) 100vw, 317px\"></p>','Furnaround','','inherit','closed','closed','','78-revision-v1','','','2016-02-26 14:06:49','2016-02-26 14:06:49','','78','http://open-me.info/hinec.org.uk-v2/78-revision-v1/',0,'revision','',0);
INSERT INTO `wp_ytazrs7z61_posts` VALUES ('129','3','2016-02-26 14:50:40','2016-02-26 14:50:40','<h3>‘People deserve care and love in their time of need’</h3>\r\n<p>We work together with the management of Macclesfield Town Centre and the Police to help people, whoever they are and whatever their situation, by listening, caring, offering practical help or referring them to specialist agencies.</p>\r\n<p>As volunteers from the local churches we walk around the town on Saturday nights (from 10.30pm - 3.00am):</p>\r\n<ul>\r\n<li>providing a Christian presence</li>\r\n<li>giving free bottles of water</li>\r\n<li>helping out with free flip-flops for those who need them</li>\r\n<li>lending a listening ear to those whose evening has not turned out so well</li>\r\n<li>giving simple first aid</li>\r\n<li>inviting those who need a warm drink back to the United Reformed Church, our centre</li>\r\n<li>referring those who are in dire need to the emergency services</li>\r\n</ul>\r\n<p>&nbsp;</p>\r\n<p>I would like to consider helping with Street Angels Macclesfield on a Saturday evening:</p>\r\n<ul>\r\n<li>Please contact your church leader or administrator</li>\r\n<li>email streetangelsmacclesfield@gmail.com</li>\r\n<li>or call Pip Mosscrop Street Angels coordinator on 07715 495701</li>\r\n</ul>\r\n<img src=\"http://open-me.info/hinec.org.uk-v2/wp-content/uploads/logo-hope-street-angels-317-160.png\" width=\"317\" height=\"160\" srcset=\"http://open-me.info/hinec.org.uk-v2/wp-content/uploads/logo-hope-street-angels-317-160-300x151.png 300w, http://open-me.info/hinec.org.uk-v2/wp-content/uploads/logo-hope-street-angels-317-160.png 317w\" class=\"so-widget-image\">','Street Angels','','inherit','closed','closed','','61-revision-v1','','','2016-02-26 14:50:40','2016-02-26 14:50:40','','61','http://open-me.info/hinec.org.uk-v2/61-revision-v1/',0,'revision','',0);
