INSERT INTO `wp_ytazrs7z61_posts` VALUES ('131','3','2016-02-26 14:55:56','2016-02-26 14:55:56','<h3>‘People deserve care and love in their time of need’</h3>\r\n<p>We work together with the management of Macclesfield Town Centre and the Police to help people, whoever they are and whatever their situation, by listening, caring, offering practical help or referring them to specialist agencies.</p>\r\n<p>As volunteers from the local churches we walk around the town on Saturday nights (from 10.30pm - 3.00am):</p>\r\n<ul>\r\n<li>providing a Christian presence</li>\r\n<li>giving free bottles of water</li>\r\n<li>helping out with free flip-flops for those who need them</li>\r\n<li>lending a listening ear to those whose evening has not turned out so well</li>\r\n<li>giving simple first aid</li>\r\n<li>inviting those who need a warm drink back to the United Reformed Church, our centre</li>\r\n<li>referring those who are in dire need to the emergency services</li>\r\n</ul>\r\n<p>&nbsp;</p>\r\n<p>I would like to consider helping with Street Angels Macclesfield on a Saturday evening:</p>\r\n<ul>\r\n<li>Please contact your church leader or administrator</li>\r\n<li>email streetangelsmacclesfield@gmail.com</li>\r\n<li>or call Pip Mosscrop Street Angels coordinator on 07715 495701</li>\r\n</ul>\r\n<img src=\"http://open-me.info/hinec.org.uk-v2/wp-content/uploads/logo-hope-street-angels-317-160.png\" width=\"317\" height=\"160\" srcset=\"http://open-me.info/hinec.org.uk-v2/wp-content/uploads/logo-hope-street-angels-317-160-300x151.png 300w, http://open-me.info/hinec.org.uk-v2/wp-content/uploads/logo-hope-street-angels-317-160.png 317w\" class=\"so-widget-image\">\r\n<a href=\"http://www.sa-cni.org.uk/\">	<img src=\"http://open-me.info/hinec.org.uk-v2/wp-content/uploads/cni-network-logo.jpg\" width=\"716\" height=\"373\" srcset=\"http://open-me.info/hinec.org.uk-v2/wp-content/uploads/cni-network-logo-300x156.jpg 300w, http://open-me.info/hinec.org.uk-v2/wp-content/uploads/cni-network-logo.jpg 716w\" class=\"so-widget-image\">\r\n</a>','Street Angels','','inherit','closed','closed','','61-revision-v1','','','2016-02-26 14:55:56','2016-02-26 14:55:56','','61','http://open-me.info/hinec.org.uk-v2/61-revision-v1/',0,'revision','',0);
INSERT INTO `wp_ytazrs7z61_posts` VALUES ('132','3','2016-02-26 15:05:56','2016-02-26 15:05:56','<p><img class=\"alignright size-full wp-image-86\" src=\"http://open-me.info/hinec-test/wp-content/uploads/logo-hope-centre-317-160.jpg\" alt=\"logo-hope-centre-317-160\" width=\"316\" height=\"160\" srcset=\"http://open-me.info/hinec.org.uk-v2/wp-content/uploads/logo-hope-centre-317-160-300x152.jpg 300w, http://open-me.info/hinec.org.uk-v2/wp-content/uploads/logo-hope-centre-317-160.jpg 316w\" sizes=\"(max-width: 316px) 100vw, 316px\"></p>\n<img src=\"http://open-me.info/hinec.org.uk-v2/wp-content/uploads/logo-hope-centre-317-160.jpg\" width=\"316\" height=\"160\" srcset=\"http://open-me.info/hinec.org.uk-v2/wp-content/uploads/logo-hope-centre-317-160-300x152.jpg 300w, http://open-me.info/hinec.org.uk-v2/wp-content/uploads/logo-hope-centre-317-160.jpg 316w\" class=\"so-widget-image\">','The Hope Centre','','inherit','closed','closed','','87-autosave-v1','','','2016-02-26 15:05:56','2016-02-26 15:05:56','','87','http://open-me.info/hinec.org.uk-v2/87-autosave-v1/',0,'revision','',0);
INSERT INTO `wp_ytazrs7z61_posts` VALUES ('133','3','2016-02-26 15:07:49','2016-02-26 15:07:49','<p>The HOPE Centre welcome everyone to it\'s coffee shop and Christian bookshop, selling books, cards, and gifts. It provides a beacon of hope to the people of macclesfield and the surrounding villages.</p>\r\n<p>&nbsp;</p>\r\n<img src=\"http://open-me.info/hinec.org.uk-v2/wp-content/uploads/logo-hope-centre-317-160.jpg\" width=\"316\" height=\"160\" srcset=\"http://open-me.info/hinec.org.uk-v2/wp-content/uploads/logo-hope-centre-317-160-300x152.jpg 300w, http://open-me.info/hinec.org.uk-v2/wp-content/uploads/logo-hope-centre-317-160.jpg 316w\" class=\"so-widget-image\">','The Hope Centre','','inherit','closed','closed','','87-revision-v1','','','2016-02-26 15:07:49','2016-02-26 15:07:49','','87','http://open-me.info/hinec.org.uk-v2/87-revision-v1/',0,'revision','',0);
INSERT INTO `wp_ytazrs7z61_posts` VALUES ('134','3','2016-02-26 15:18:09','2016-02-26 15:18:09','<p>The HOPE Centre welcome everyone to it\'s coffee shop and Christian bookshop, selling books, cards, and gifts. Based at Park Green, Macclesfield, it provides a beacon of hope to the people of Macclesfield.</p>\r\n<p>We stock a range of Christian resources (available and to order) including Bibles in various translations, Bible reading notes, Junior church, church resources, holiday clubs, messy church, study guides for house groups.&nbsp;We have Bible commentaries, concordances, study guides,&nbsp;Childrens activity books, pocket money gifts and novelty items,&nbsp;CDs and music resources.</p>\r\n<p>A large selection of cards is available&nbsp;for all occasions: Gifts including first communion, confirmation, baptism, jewellry, games, seasonal presents, stationery, mass cards and rosaries.&nbsp;</p>\r\n<p>We will also order any book or Bible from our suppliers.</p>\r\n<p>Visit <a href=\"http://www.hopecentremacclesfield.org.uk\">The Hope Centre website</a>.</p>\r\n<img src=\"http://open-me.info/hinec.org.uk-v2/wp-content/uploads/logo-hope-centre-317-160.jpg\" width=\"316\" height=\"160\" srcset=\"http://open-me.info/hinec.org.uk-v2/wp-content/uploads/logo-hope-centre-317-160-300x152.jpg 300w, http://open-me.info/hinec.org.uk-v2/wp-content/uploads/logo-hope-centre-317-160.jpg 316w\" class=\"so-widget-image\">','The Hope Centre','','inherit','closed','closed','','87-revision-v1','','','2016-02-26 15:18:09','2016-02-26 15:18:09','','87','http://open-me.info/hinec.org.uk-v2/87-revision-v1/',0,'revision','',0);
