INSERT INTO `wp_ytazrs7z61_posts` VALUES ('198','3','2016-08-01 18:28:34','2016-08-01 17:28:34','<h3 class=\"widget-title\">Cheshire Streetwise Furniture Project</h3>\r\n<b><u></u></b>With the support of Churches and volunteers in Macclesfield, Cheshire Streetwise is combating poverty through the provision of furniture and other household items to those in need in the areas of Macclesfield and Congleton. The furniture project contributes items to the Emergency Assistance Scheme operated by Cheshire East and also provides furniture to individuals and families through referrals from local agencies and churches. Volunteers currently collect and deliver furniture two to three days a week and run a shop at Gilchrist Avenue, Macclesfield for four days a week (Monday, Tuesday, Thursday 10-4.00, Saturday 10-12.00). Visitors are always welcome for a cup of tea and a chat. Cheshire Streetwise is committed to providing education, support and counselling to a wide range of children and adults with a variety of needs and also provides tuition, a skills cafe, counselling, foodbank and signposting service. To arrange collections, referrals or for general enquiries call 07469 176811     <i>Like: Facebook at <a href=\"http://www.facebook.com/CheshireFurnitureReuse\" target=\"_blank\" rel=\"nofollow\" shape=\"rect\" data-saferedirecturl=\"https://www.google.com/url?q=http://www.facebook.com/CheshireFurnitureReuse&amp;source=gmail&amp;ust=1470158779612000&amp;usg=AFQjCNH4yTeAaHB3Pi7UJOJq_l_tXZShyQ\">www.facebook.com/<wbr />CheshireFurnitureReuse</a></i> <i>Follow: CheshreReuse @CFRFCoordinator</i> <i>Visit: <a href=\"http://www.cfrf.org.uk/\" target=\"_blank\" rel=\"nofollow\" shape=\"rect\" data-saferedirecturl=\"https://www.google.com/url?q=http://www.cfrf.org.uk/&amp;source=gmail&amp;ust=1470158779612000&amp;usg=AFQjCNEdvpjqJqgsTDIqk5PSj5l1uTeeyw\">http://www.cfrf.org.uk/</a></i>','Cheshire Streetwise Furniture Project','','inherit','closed','closed','','78-revision-v1','','','2016-08-01 18:28:34','2016-08-01 17:28:34','','78','https://hinec.org.uk/78-revision-v1/',0,'revision','',0);
INSERT INTO `wp_ytazrs7z61_posts` VALUES ('199','3','2016-08-01 18:30:43','2016-08-01 17:30:43','<b><u></u></b>With the support of Churches and volunteers in Macclesfield, Cheshire Streetwise is combating poverty through the provision of furniture and other household items to those in need in the areas of Macclesfield and Congleton.   The furniture project contributes items to the Emergency Assistance Scheme operated by Cheshire East and also provides furniture to individuals and families through referrals from local agencies and churches.   Volunteers currently collect and deliver furniture two to three days a week and run a shop at Gilchrist Avenue, Macclesfield for four days a week (Monday, Tuesday, Thursday 10.00-4.00, Saturday 10.00-12.00). Visitors are always welcome for a cup of tea and a chat.   Cheshire Streetwise is committed to providing education, support and counselling to a wide range of children and adults with a variety of needs and also provides tuition, a skills cafe, counselling, foodbank and signposting service.   To arrange collections, referrals or for general enquiries call 07469 176811     <i>Like: Facebook at <a href=\"http://www.facebook.com/CheshireFurnitureReuse\" target=\"_blank\" rel=\"nofollow\" shape=\"rect\" data-saferedirecturl=\"https://www.google.com/url?q=http://www.facebook.com/CheshireFurnitureReuse&amp;source=gmail&amp;ust=1470158779612000&amp;usg=AFQjCNH4yTeAaHB3Pi7UJOJq_l_tXZShyQ\">www.facebook.com/<wbr />CheshireFurnitureReuse</a></i> <i>Follow: CheshreReuse @CFRFCoordinator</i> <i>Visit: <a href=\"http://www.cfrf.org.uk/\" target=\"_blank\" rel=\"nofollow\" shape=\"rect\" data-saferedirecturl=\"https://www.google.com/url?q=http://www.cfrf.org.uk/&amp;source=gmail&amp;ust=1470158779612000&amp;usg=AFQjCNEdvpjqJqgsTDIqk5PSj5l1uTeeyw\">http://www.cfrf.org.uk/</a></i>','Cheshire Streetwise Furniture Project','','inherit','closed','closed','','78-revision-v1','','','2016-08-01 18:30:43','2016-08-01 17:30:43','','78','https://hin