INSERT INTO `wp_ytazrs7z61_posts` VALUES ('209','3','2017-05-21 16:36:00','2017-05-21 15:36:00','One of Macclesfield’s best kept secrets is the amount of social action being provided by small local organisations, and the huge amount of volunteering to provide help where it’s needed. You can access the booklet about the organisations, a video of their work, and contact details below:\r\n\r\n<a href=\"/wp-content/uploads/Social-Action-Booklet.pdf\">What\'s going on? Information booklet</a>\r\n\r\n<a href=\"/organisation-contacts/\">What\'s going on? Organisation details</a>\r\n\r\n\r\nThis video features short introductions to 11 organisations who are participating in the \'What\'s going on?\' event\r\nhttps://youtu.be/jpE-8GGg6v8\r\n','What\'s Going On? Social Action Marketplace','','publish','closed','closed','','whatsgoingon','','','2018-01-02 15:53:40','2018-01-02 14:53:40','','0','https://hinec.org.uk/?page_id=209',0,'page','',0);
