INSERT INTO `wp_ytazrs7z61_posts` VALUES ('240','3','2017-12-31 15:54:19','2017-12-31 14:54:19','<!-- wp:paragraph {\"align\":\"left\",\"fontSize\":\"medium\"} -->\n<p class=\"has-text-align-left has-medium-font-size\"></p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph {\"align\":\"left\",\"fontSize\":\"medium\"} -->\n<p class=\"has-text-align-left has-medium-font-size\"> Citizen Advice Services in East Cheshire </p>\n<!-- /wp:paragraph -->\n\n<!-- wp:list -->\n<ul><!-- wp:list-item -->\n<li>Website: <a href=\"https://www.citizensadvicecn.org.uk/\">www.citizensadvicecn.org.uk</a> </li>\n<!-- /wp:list-item --></ul>\n<!-- /wp:list -->\n\n<!-- wp:separator {\"opacity\":\"css\",\"backgroundColor\":\"pale-cyan-blue\"} -->\n<hr class=\"wp-block-separator has-text-color has-pale-cyan-blue-color has-css-opacity has-pale-cyan-blue-background-color has-background\"/>\n<!-- /wp:separator -->\n\n<!-- wp:paragraph {\"fontSize\":\"medium\"} -->\n<p class=\"has-medium-font-size\">Cre8 Youth and Community Programme</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:list -->\n<ul><!-- wp:list-item -->\n<li>Website: <a rel=\"noreferrer noopener\" href=\"http://cre8macclesfield.org\" target=\"_blank\">www.cre8macclesfield.org</a></li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>Facebook:&nbsp;<a rel=\"noreferrer noopener\" href=\"http://www.facebook.com/cre8macclesfield\" target=\"_blank\">www.facebook.com/cre8macclesfield</a></li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>Operations Manager: Jonathan Aiken</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>Project Cre8 Grow Co-ordinator: Emily Gunnion</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>email: hello@cre8macclesfield.org</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>phone: 01625 503740</li>\n<!-- /wp:list-item --></ul>\n<!-- /wp:list -->\n\n<!-- wp:separator {\"opacity\":\"css\",\"backgroundColor\":\"pale-cyan-blue\"} -->\n<hr class=\"wp-block-separator has-text-color has-pale-cyan-