INSERT INTO `wp_ytazrs7z61_posts` VALUES ('258','3','2018-01-02 10:44:33','2018-01-02 09:44:33','<div id=\"pl-258\"  class=\"panel-layout\" ><div id=\"pg-258-0\"  class=\"panel-grid panel-no-style\" ><div id=\"pgc-258-0-0\"  class=\"panel-grid-cell\"  data-weight=\"1\" ><div id=\"panel-258-0-0-0\" class=\"so-panel widget widget_sow-editor panel-first-child panel-last-child\" data-index=\"0\" data-style=\"{&quot;background_display&quot;:&quot;tile&quot;}\" ><div class=\"so-widget-sow-editor so-widget-sow-editor-base\">\n<div class=\"siteorigin-widget-tinymce textwidget\">\n	<h1 style=\"text-align: center;\">HOPE IN NORTH EAST CHESHIRE</h1>\n\n<hr />\n\n<h4 style=\"line-height:1.4em;\">Hope in North East Cheshire (Hope) encourages shared initiatives in mission and service and organises joint gatherings for worship and prayer. It also responds to requests for information, help and funding, working closely with many voluntary organisations, a number represented here, and the statutory authorities.\n<br />\nIncorporating Churches Together in Macclesfield and Bollington, and affiliated to Churches Together in Britain and Ireland, Hope was established in 2009 bringing together some thirty-nine Churches of many denominations in Macclesfield, Bollington and the surrounding villages. The Church Leaders meet regularly for prayer, worship, fellowship and discussion, while small groups of Leaders and lay people plan Hope’s priorities, review progress and relationships, and manage its finances.\n<br />\nHope involves lots of volunteers, many from the local Churches, in a wide range of initiatives which any one Church would find difficult to sustain. It encourages like-minded people to come together to respond to their calling and to share their passions to make things happen for the benefit of the community.\n<br />\n<span style=\"color: #00ccff;\">Proclaiming the Gospel through Social Action in Macclesfield and Bollington and the surrounding villages.</span></h4></div>\n</div></div></div></div><div id=\"pg-258-1\"  class=\"panel-grid panel-no-style\" ><div id=\"pgc-258-1-0\"  class=\"panel-grid-cell\"  data-weight=\"0.33333333333333\" ><div id=\"panel-258-1-0-0\" class=\"so-panel widget widget_sow-image panel-first-child panel-last-child\" data-index=\"1\" data-style=\"{&quot;background_display&quot;:&quot;tile&quot;}\" >[siteorigin_widget class=\"SiteOrigin_Widget_Image_Widget\"]<input type=\"hidden\" value=\"{&quot;instance&quot;:{&quot;image&quot;:75,&quot;image_fallback&quot;:&quot;&quot;,&quot;size&quot;:&quot;full&quot;,&quot;align&quot;:&quot;default&quot;,&quot;title&quot;:&quot;Just Drop In&quot;,&quot;title_position&quot;:&quot;hidden&quot;,&quot;alt&quot;:&quot;&quot;,&quot;url&quot;:&quot;\\/just-drop-in&quot;,&quot;bound&quot;:true,&quot;_sow_form_id&quot;:&quot;56c866d1b451d&quot;,&quot;_sow_form_timestamp&quot;:&quot;&quot;,&quot;new_window&quot;:false,&quot;full_width&quot;:false},&quot;args&quot;:{&quot;before_widget&quot;:&quot;&lt;div id=\\&quot;panel-258-1-0-0\\&quot; class=\\&quot;so-panel widget widget_sow-image panel-first-child panel-last-child\\&quot; data-index=\\&quot;1\\&quot; data-style=\\&quot;{&amp;quot;background_display&amp;quot;:&amp;quot;tile&amp;quot;}\\&quot; &gt;&quot;,&quot;after_widget&quot;:&quot;&lt;\\/div&gt;&quot;,&quot;before_title&quot;:&quot;&lt;h3 class=\\&quot;widget-title\\&quot;&gt;&quot;,&quot;after_title&quot;:&quot;&lt;\\/h3&gt;&quot;,&quot;widget_id&quot;:&quot;widget-1-0-0&quot;}}\" />[/siteorigin_widget]</div></div><div id=\"pgc-258-1-1\"  class=\"panel-grid-cell\"  data-weight=\"0.33333333333333\" ><div id=\"panel-258-1-1-0\" class=\"so-panel widget widget_sow-image panel-first-child panel-last-child\" data-index=\"2\" data-style=\"{&quot;background_display&quot;:&quot;tile&quot;}\" >[siteorigin_widget class=\"SiteOrigin_Widget_Image_Widget\"]<input type=\"hidden\" value=\"{&quot;instance&quot;:{&quot;image&quot;:86,&quot;image_fallback&quot;:&quot;&quot;,&quot;size&quot;:&quot;full