INSERT INTO `wp_ytazrs7z61_posts` VALUES ('270','3','2018-01-02 15:42:33','2018-01-02 14:42:33','<div class=\"page\" title=\"Page 2\">\r\n<div class=\"section\">\r\n<div class=\"layoutArea\">\r\n<div class=\"column\">\r\n\r\nOne of Macclesfield’s best kept secrets is the amount of social action being provided by small local organisations, and the huge amount of volunteering to provide help where it’s needed. You can access the booklet about the organisations, a video of their work, and contact details below:\r\n\r\n</div>\r\n<a href=\"/wp-content/uploads/Social-Action-Booklet.pdf\">What\'s going on? Information booklet</a>\r\n\r\n<a href=\"/whats-going-on-video/\">What\'s going on? Video</a>\r\n\r\n<a href=\"/organisation-contacts/\">What\'s going on? Contact details</a>\r\n\r\n</div>\r\n&nbsp;\r\n\r\n</div>\r\n</div>','What\'s Going On? Social Action Marketplace','','inherit','closed','closed','','209-revision-v1','','','2018-01-02 15:42:33','2018-01-02 14:42:33','','209','https://hinec.org.uk/209-revision-v1/',0,'revision','',0);
INSERT INTO `wp_ytazrs7z61_posts` VALUES ('271','3','2018-01-02 15:43:17','2018-01-02 14:43:17','Here are contact emails for the organisations featured in the \'What\'s going on\' event\r\n<table>\r\n<tbody>\r\n<tr>\r\n<td width=\"135\"><strong>Organisation</strong></td>\r\n<td width=\"291\"><strong>Email</strong></td>\r\n</tr>\r\n<tr>\r\n<td width=\"135\">Cre8</td>\r\n<td width=\"291\">Katy.wardle@cre8macclesfield.org</td>\r\n</tr>\r\n<tr>\r\n<td width=\"135\">WHAM</td>\r\n<td width=\"291\">david.wightman1@ntlworld.com</td>\r\n</tr>\r\n<tr>\r\n<td width=\"135\">Street Angels</td>\r\n<td width=\"291\">pipmosscrop2@yahoo.co.uk</td>\r\n</tr>\r\n<tr>\r\n<td width=\"135\">Treehouse</td>\r\n<td width=\"291\">louise.wiliamson6@aol.co.uk</td>\r\n</tr>\r\n<tr>\r\n<td width=\"135\">Just Drop In</td>\r\n<td width=\"291\">ann.wright@justdropin.co.uk</td>\r\n</tr>\r\n<tr>\r\n<td width=\"135\">Silk Life Foodbank</td>\r\n<td width=\"291\">http://www.silklifefoodbank.co.uk/foodbank/contact/contact-donate-support/</td>\r\n</tr>\r\n<tr>\r\n<td width=\"135\">Golden Memories</td>\r\n<td width=\"291\">Bob-boland@jerome-associates.co.uk</td>\r\n</tr>\r\n<tr>\r\n<td width=\"135\">Cheshire Streetwise</td>\r\n<td width=\"291\">info@cheshirestreetwise.co.uk</td>\r\n</tr>\r\n<tr>\r\n<td width=\"135\">ROAR</td>\r\n<td width=\"291\">jillmillward@reachoutandrecover.org</td>\r\n</tr>\r\n<tr>\r\n<td width=\"135\">Citizens Advice Bureau</td>\r\n<td width=\"291\">advice @ CECAB-North.org.uk</td>\r\n</tr>\r\n<tr>\r\n<td width=\"135\">Eco Group</td>\r\n<td width=\"291\">davidjmayers@btinternet.com</td>\r\n</tr>\r\n</tbody>\r\n</table>','\'What\'s Going On?\' contact info','','inherit','closed','closed','','222-revision-v1','','','2018-01-02 15:43:17','2018-01-02 14:43:17','','222','https://hinec.org.uk/222-revision-v1/',0,'revision','',0);
