h -->\n\n<!-- wp:list -->\n<ul><li> Website: <a rel=\"noreferrer noopener\" href=\"http://www.justdropin.co.uk\" target=\"_blank\">www.justdropin.co.uk</a></li><li> Manager: Ann Wright<ul><li>email: hello@justdropin.co uk</li><li>telephone: 01625 665079 </li></ul></li></ul>\n<!-- /wp:list -->\n\n<!-- wp:separator {\"color\":\"pale-cyan-blue\"} -->\n<hr class=\"wp-block-separator has-text-color has-background has-pale-cyan-blue-background-color has-pale-cyan-blue-color\"/>\n<!-- /wp:separator -->\n\n<!-- wp:paragraph {\"fontSize\":\"medium\"} -->\n<p class=\"has-medium-font-size\">Open the Book</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:list -->\n<ul><li> Co-ordinator: Dot Phillips<ul><li>email: dotphillips@outlook.com</li><li>telephone: 01625 260607 </li></ul></li></ul>\n<!-- /wp:list -->\n\n<!-- wp:separator {\"color\":\"pale-cyan-blue\"} -->\n<hr class=\"wp-block-separator has-text-color has-background has-pale-cyan-blue-background-color has-pale-cyan-blue-color\"/>\n<!-- /wp:separator -->\n\n<!-- wp:paragraph {\"fontSize\":\"medium\"} -->\n<p class=\"has-medium-font-size\">Silklife Foodbank</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:list -->\n<ul><li>Facebook:&nbsp;<a rel=\"noreferrer noopener\" href=\"http://www.facebook.com/silklifefoodbank\" target=\"_blank\">www.facebook.com/silklifefoodbank</a></li><li>email: foodbank@silklife.co.uk</li><li>telephone: 07895 85007</li></ul>\n<!-- /wp:list -->\n\n<!-- wp:separator {\"color\":\"pale-cyan-blue\"} -->\n<hr class=\"wp-block-separator has-text-color has-background has-pale-cyan-blue-background-color has-pale-cyan-blue-color\"/>\n<!-- /wp:separator -->\n\n<!-- wp:paragraph {\"fontSize\":\"medium\"} -->\n<p class=\"has-medium-font-size\"> Street Angels </p>\n<!-- /wp:paragraph -->\n\n<!-- wp:list -->\n<ul><li>email: streetangelsmacclesfield@gmail.com</li><li>telephone: 07494 805487</li><li>Co-ordinator: Pip Mosscrop<ul><li>email: pipmosscrop2@yahoo.co.uk</li><li>telephone: 07494 805487</li></ul></li></ul>\n<!-- /wp:list -->\n\n<!-- wp:separator {\"color\":\"pale-cyan-blue\"} -->\n<hr class=\"wp-block-separator has-text-color has-background has-pale-cyan-blue-background-color has-pale-cyan-blue-color\"/>\n<!-- /wp:separator -->\n\n<!-- wp:paragraph {\"fontSize\":\"medium\"} -->\n<p class=\"has-medium-font-size\">WHAM Nightshelter</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:list -->\n<ul><li>telephone:&nbsp;07874 852762 (Volunteers)</li><li>telephone: 07570 559483 (Referrals)</li><li>Co-ordinator: Rachel Mayers<ul><li>email: maccnightshelter@gmail.com </li></ul></li></ul>\n<!-- /wp:list -->\n\n<!-- wp:separator {\"color\":\"pale-cyan-blue\"} -->\n<hr class=\"wp-block-separator has-text-color has-background has-pale-cyan-blue-background-color has-pale-cyan-blue-color\"/>\n<!-- /wp:separator -->\n\n<!-- wp:paragraph {\"fontSize\":\"medium\"} -->\n<p class=\"has-medium-font-size\"> Macclesfield Community Kitchen (MCK) </p>\n<!-- /wp:paragraph -->\n\n<!-- wp:list -->\n<ul><li> Co-ordinator: Claire Hammond<ul><li>email: macclesfieldcommunitykitchen@gmail.com </li></ul></li></ul>\n<!-- /wp:list -->\n\n<!-- wp:separator {\"color\":\"pale-cyan-blue\"} -->\n<hr class=\"wp-block-separator has-text-color has-background has-pale-cyan-blue-background-color has-pale-cyan-blue-color\"/>\n<!-- /wp:separator -->\n\n<!-- wp:paragraph {\"fontSize\":\"medium\"} -->\n<p class=\"has-medium-font-size\">ROAR (Reach Out and Recover)</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:list -->\n<ul><li> Website: <a href=\"http://www.reachoutandrecover.org\">http://www.reachoutandrecover.org</a></li><li> Founders: Jill and Vicky Millward<ul><li>email: jillmillward@reachoutandrecover.org</li><li>email: vickymillward@reachoutandrecover.org</li><li>telephone: 01625 619106 </li></ul></li></ul>\n<!-- /wp:list -->\n\n<!-- wp:separator {\"color\":\"pale-cyan-blue\"} -->\n<hr class=\"wp-block-separator has-text-color has-background has-pale-cyan-blue-background-color has-pale-cyan-blue-color\"/>\n<!-- /wp:separator -->\n\n<!-- wp:paragraph