INSERT INTO `wp_ytazrs7z61_posts` VALUES ('371','3','2024-02-07 16:54:20','2024-02-07 15:54:20','<!-- wp:paragraph {\"fontSize\":\"medium\"} -->\n<p class=\"has-medium-font-size\"></p>\n<!-- /wp:paragraph -->\n\n<!-- wp:list {\"ordered\":true} -->\n<ol><!-- wp:list-item -->\n<li>Continue to provide an environment that encourages church leaders to meet together and to selflessly support and help each other.</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>Grow a stronger relationship with leaders and churches who currently are not active within Hope.</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>Build stronger links between the churches and communities that we serve, including through even greater sharing of resources, ideas and best practice.</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>More clearly communicate our purpose, plans and stories to churches and local communities including through greater use of social media.</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>Provide opportunities for existing church members to grow in faith through service and shared discipleship.</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>Create and deliver a credible, resourceable plan to reach out with the gospel message to people in the community (e.g. hold at least 1 town-wide outreach event pa and grow the Treacle Market prayer-walking initiative).</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>Re-draw our plan for social action, identify new activities and adjusting existing activities... to best meet community needs, especially for the disadvantaged and marginalised.</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>Keep things simple, low in formality, true and Spirit-led.</li>\n<!-- /wp:list-item --></ol>\n<!-- /wp:list -->\n\n<!-- wp:paragraph -->\n<p></p>\n<!-- /wp:paragraph -->','Strategic Priorities 2024-2026','','publish','closed','closed','','strategic-priorities','','','2024-07-19 12:07:29','2024-07-19 11:07:29','','0','http://www.chokmah.uk/?page_id=371',0,'page','',0);
INSERT INTO `wp_ytazrs7z61_posts` VALUES ('372','3','2024-02-07 16:43:50','2024-02-07 15:43:50','','Strategic Priorities','','inherit','closed','closed','','371-revision-v1','','','2024-02-07 16:43:50','2024-02-07 15:43:50','','371','http://www.chokmah.uk/371-revision-v1/',0,'revision','',0);
INSERT INTO `wp_ytazrs7z61_posts` VALUES ('373','3','2024-02-07 16:54:20','2024-02-07 15:54:20','<!-- wp:paragraph {\"fontSize\":\"medium\"} -->\n<p class=\"has-medium-font-size\">Our strategic priorities for the next 3 years</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:list {\"ordered\":true} -->\n<ol><li>Continue to provide an environment that encourages church leaders to meet together and to selflessly support and help each other.</li><li>Grow a stronger relationship with leaders and churches who currently are not active within Hope.</li><li>Build stronger links between the churches and communities that we serve, including through evengreater sharing of resources, ideas and best practice.</li><li>More clearly communicate our purpose, plans and stories to churches and local communities including through greater use of social media.</li><li>Provide opportunities for existing church members to grow in faith through service and shared discipleship.</li><li>Create and deliver a credible , resourceable plan to reach out with the gospel message to people in the community (e.g. hold at least 1 town-wide outreach event pa and grow the Treacle Market prayer-walking initiative).</li><li>Re-draw our plan for social action, identify new activities and adjusting existing activities... to best meet community needs, especially for the disadvantaged and marginalised.</li><li>Keep things simple, low in formality, true and Spirit-led.</li></ol>\n<!-- /wp:list -->\n\n<!-- wp:paragraph -->\n<p></p>\n<!-- /wp:paragraph -->','Strategic Priorities','','inherit','closed','closed','','371-revision-v1','','','2024-02-07 16:54:20','2024-02-07 15:54:20','','371','http://www.chokmah.uk/371-revision-v1/',0,'revision','',0);
