e&quot;:&quot;full&quot;,&quot;size_width&quot;:&quot;&quot;,&quot;size_height&quot;:&quot;&quot;,&quot;size_external&quot;:&quot;custom_size&quot;,&quot;size_external_width&quot;:&quot;&quot;,&quot;size_external_height&quot;:&quot;&quot;,&quot;align&quot;:&quot;default&quot;,&quot;title_align&quot;:&quot;default&quot;,&quot;title&quot;:&quot;&quot;,&quot;title_position&quot;:&quot;hidden&quot;,&quot;alt&quot;:&quot;&quot;,&quot;url&quot;:&quot;&quot;,&quot;bound&quot;:true,&quot;rel&quot;:&quot;&quot;,&quot;image_shape&quot;:{&quot;shape&quot;:&quot;circle&quot;,&quot;repeat&quot;:&quot;no-repeat&quot;,&quot;size&quot;:&quot;&quot;,&quot;size_unit&quot;:&quot;px&quot;,&quot;alignment&quot;:&quot;center&quot;,&quot;so_field_container_state&quot;:&quot;open&quot;,&quot;enable&quot;:&quot;&quot;},&quot;_sow_form_id&quot;:&quot;56d0675aa7935&quot;,&quot;_sow_form_timestamp&quot;:&quot;1709907344343&quot;,&quot;link_title&quot;:&quot;&quot;,&quot;new_window&quot;:&quot;&quot;,&quot;full_width&quot;:&quot;&quot;,&quot;so_sidebar_emulator_id&quot;:&quot;sow-image-6110002&quot;,&quot;option_name&quot;:&quot;widget_sow-image&quot;},&quot;args&quot;:{&quot;before_widget&quot;:&quot;&lt;div id=\\&quot;panel-61-0-1-1\\&quot; class=\\&quot;so-panel widget widget_sow-image panel-last-child\\&quot; data-index=\\&quot;2\\&quot; data-style=\\&quot;{&amp;quot;background_image_attachment&amp;quot;:false,&amp;quot;background_display&amp;quot;:&amp;quot;tile&amp;quot;,&amp;quot;background_image_size&amp;quot;:&amp;quot;full&amp;quot;,&amp;quot;background_image_opacity&amp;quot;:&amp;quot;100&amp;quot;,&amp;quot;border_thickness&amp;quot;:&amp;quot;1px&amp;quot;}\\&quot; &gt;&quot;,&quot;after_widget&quot;:&quot;&lt;\\/div&gt;&quot;,&quot;before_title&quot;:&quot;&lt;h3 class=\\&quot;widget-title\\&quot;&gt;&quot;,&quot;after_title&quot;:&quot;&lt;\\/h3&gt;&quot;,&quot;widget_id&quot;:&quot;widget-0-1-1&quot;}}\" />[/siteorigin_widget]</div></div></div></div>','Street Angels','','inheri