INSERT INTO `wp_ytazrs7z61_posts` VALUES ('412','3','2024-03-09 21:28:02','2024-03-09 20:28:02','<!-- wp:paragraph {\"align\":\"left\",\"fontSize\":\"medium\"} -->\n<p class=\"has-text-align-left has-medium-font-size\"></p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph {\"align\":\"left\",\"fontSize\":\"medium\"} -->\n<p class=\"has-text-align-left has-medium-font-size\"> Citizen Advice Services in East Cheshire </p>\n<!-- /wp:paragraph -->\n\n<!-- wp:list -->\n<ul><!-- wp:list-item -->\n<li>Website: <a href=\"https://www.citizensadvicecn.org.uk/\">www.citizensadvicecn.org.uk</a> </li>\n<!-- /wp:list-item --></ul>\n<!-- /wp:list -->\n\n<!-- wp:separator {\"opacity\":\"css\",\"backgroundColor\":\"pale-cyan-blue\"} -->\n<hr class=\"wp-block-separator has-text-color has-pale-cyan-blue-color has-css-opacity has-pale-cyan-blue-background-color has-background\"/>\n<!-- /wp:separator -->\n\n<!-- wp:paragraph {\"fontSize\":\"medium\"} -->\n<p class=\"has-medium-font-size\">Cre8 Youth and Community Programme</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:list -->\n<ul><!-- wp:list-item -->\n<li>Website: <a rel=\"noreferrer noopener\" href=\"http://cre8macclesfield.org\" target=\"_blank\">www.cre8macclesfield.org</a></li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>Facebook:&nbsp;<a rel=\"noreferrer noopener\" href=\"http://www.facebook.com/cre8macclesfield\" target=\"_blank\">www.facebook.com/cre8macclesfield</a></li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>Director: Ameera Fletcher</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>Project Grow Co-ordinator: Katy Wardle<!-- wp:list -->\n<ul><!-- wp:list-item -->\n<li>email: hello@cre8macclesfield.org</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>telephone: 01625 503740</li>\n<!-- /wp:list-item --></ul>\n<!-- /wp:list --></li>\n<!-- /wp:list-item --></ul>\n<!-- /wp:list -->\n\n<!-- wp:separator {\"opacity\":\"css\",\"backgroundColor\":\"pale-cyan-blue\"} -->\n<hr class=\"wp-block-separator has-text-color has-pale-cyan-blue-color has-css-opacity has-pale-cyan-blue-background-color has-background\"/>\n<!-- /wp:separator -->\n\n<!-- wp:paragraph {\"fontSize\":\"medium\"} -->\n<p class=\"has-medium-font-size\">Eco-Church in the Community</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:list -->\n<ul><!-- wp:list-item -->\n<li>Co-ordinator: David Mayers<!-- wp:list -->\n<ul><!-- wp:list-item -->\n<li>email: davidjmayers@btinternet.com</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>telephone: 01625 420716 </li>\n<!-- /wp:list-item --></ul>\n<!-- /wp:list --></li>\n<!-- /wp:list-item --></ul>\n<!-- /wp:list -->\n\n<!-- wp:separator {\"opacity\":\"css\",\"backgroundColor\":\"pale-cyan-blue\"} -->\n<hr class=\"wp-block-separator has-text-color has-pale-cyan-blue-color has-css-opacity has-pale-cyan-blue-background-color has-background\"/>\n<!-- /wp:separator -->\n\n<!-- wp:paragraph {\"fontSize\":\"medium\"} -->\n<p class=\"has-medium-font-size\">Golden Memories</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:list -->\n<ul><!-- wp:list-item -->\n<li>Organiser : Bob Bowland<!-- wp:list -->\n<ul><!-- wp:list-item -->\n<li>email: bob-boland@jerome-associates.co.uk </li>\n<!-- /wp:list-item --></ul>\n<!-- /wp:list --></li>\n<!-- /wp:list-item --></ul>\n<!-- /wp:list -->\n\n<!-- wp:separator {\"opacity\":\"css\",\"backgroundColor\":\"pale-cyan-blue\"} -->\n<hr class=\"wp-block-separator has-text-color has-pale-cyan-blue-color has-css-opacity has-pale-cyan-blue-background-color has-background\"/>\n<!-- /wp:separator -->\n\n<!-- wp:paragraph {\"fontSize\":\"medium\"} -->\n<p class=\"has-medium-font-size\">The Hope Centre</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:list -->\n<ul><!-- wp:list-item -->\n<li> Website: <a rel=\"noreferrer noopener\" href=\"http://hopecentremacclesfield.org.uk\" target=\"_blank\">www.hopecentremacclesfield.org.uk</a></li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>Manager:<!-- wp:list -->\n<ul><!-- wp:list-item -->\n<li>email: manager@hopecentremacclesfield.org.uk</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>telephone: 01625 404384 </li>\n<!-- /wp:list-item --></ul>\n<!-- /wp:list --></li>\n<!-- /wp:list-item --></ul>\n<!-- /wp:list -->\n\n<!-- wp:separator {\"opacity\":\"css\",\"backgroundColor\":\"pale-cyan-blue\"} -->\n<hr class=\"wp-block-separator has-text-color has-pale-cyan-blue-color has-css-opacity has-pale-cyan-blue-background-color has-background\"/>\n<!-- /wp:separator -->\n\n<!-- wp:paragraph {\"fontSize\":\"medium\"} -->\n<p class=\"has-medium-font-size\">Just Drop-in</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:list -->\n<ul><!-- wp:list-item -->\n<li> Website: <a rel=\"noreferrer noopener\" href=\"http://www.justdropin.co.uk\" target=\"_blank\">www.justdropin.co.uk</a></li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>Manager: Ann Wright<!-- wp:list -->\n<ul><!-- wp:list-item -->\n<li>email: hello@justdropin.co uk</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>telephone: 01625 665079 </li>\n<!-- /wp:list-item --></ul>\n<!-- /wp:list --></li>\n<!-- /wp:list-item --></ul>\n<!-- /wp:list -->\n\n<!-- wp:separator {\"opacity\":\"css\",\"backgroundColor\":\"pale-cyan-blue\"} -->\n<hr class=\"wp-block-separator has-text-color has-pale-cyan-blue-color has-css-opacity has-pale-cyan-blue-background-color has-background\"/>\n<!-- /wp:separator -->\n\n<!-- wp:paragraph {\"fontSize\":\"medium\"} -->\n<p class=\"has-medium-font-size\">Open the Book</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:list -->\n<ul><!-- wp:list-item -->\n<li>Co-ordinator: Dot Phillips<!-- wp:list -->\n<ul><!-- wp:list-item -->\n<li>email: dotphillips@outlook.com</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>telephone: 01625 260607 </li>\n<!-- /wp:list-item --></ul>\n<!-- /wp:list --></li>\n<!-- /wp:list-item --></ul>\n<!-- /wp:list -->\n\n<!-- wp:separator {\"opacity\":\"css\",\"backgroundColor\":\"pale-cyan-blue\"} -->\n<hr class=\"wp-block-separator has-text-color has-pale-cyan-blue-colo